[TestClass]
public class CustomPipelineComponentsTests
{
    private static HttpClient _httpClient = new HttpClient();
    private static string _logicAppName    = Environment.GetEnvironmentVariable("TEST_LOGIC_APP_NAME")    ?? "CustomPipelineComponents";
    private static string _subscriptionId  = Environment.GetEnvironmentVariable("TEST_AZURE_SUBSCRIPTION_ID") ?? "{subscriptionId}";
    private static string _resourceGroup   = Environment.GetEnvironmentVariable("TEST_RESOURCE_GROUP_NAME")  ?? "{resourceGroupName}";

    private string RunUrl => $"https://management.azure.com/subscriptions/{_subscriptionId}" +
        $"/resourceGroups/{_resourceGroup}/providers/Microsoft.Web/sites/{_logicAppName}" +
        $"/hostruntime/runtime/webhooks/workflow/api/management/workflows/CustomPipelineComponents" +
        "/triggers/trigger/run?api-version=2022-03-01";

    [TestMethod]
    [Description("Happy path: Unknown — no activating receive shape found triggers workflow and all steps succeed.")]
    public async Task CustomPipelineComponents_HappyPath()
    {
        // Arrange
        var payload = {
            "messageType": "flat-file",
            "source": "Unknown — no activating receive shape found",
            "timestamp": "2026-02-28T21:57:47.436Z"
        };

        // Act
        var (statusCode, responseBody) = await TriggerWorkflow(payload);

        // Assert
        Assert.IsTrue(statusCode is 200 or 202, $"Expected 200/202 but got {statusCode}. Body: {responseBody}");
        // Workflow should be accepted (202) on valid trigger
        // Assert: @outputs('trigger')?['statusCode'] == 202
    }

    [TestMethod]
    [Description("Error path: first send step fails, error handler activates.")]
    public async Task CustomPipelineComponents_ErrorPath()
    {
        // Arrange
        var payload = {
            "messageType": "flat-file",
            "source": "Unknown — no activating receive shape found",
            "timestamp": "2026-02-28T21:57:47.436Z"
        };

        // Act
        var (statusCode, responseBody) = await TriggerWorkflow(payload);

        // Assert
        Assert.IsTrue(statusCode is 200 or 202, $"Expected 200/202 but got {statusCode}. Body: {responseBody}");
        // Main scope should show Failed status when a step errors
        // Assert: @result('Scope_Main')?[0]?['status'] == "Failed"
    }

    private async Task<(int StatusCode, string Body)> TriggerWorkflow(object payload)
    {
        var json    = JsonSerializer.Serialize(payload);
        var content = new StringContent(json, Encoding.UTF8, "application/json");
        var resp    = await _httpClient.PostAsync(RunUrl, content);
        var body    = await resp.Content.ReadAsStringAsync();
        return ((int)resp.StatusCode, body);
    }
